import{j as a,b as i,c as e,aa as l}from"./chunks/framework.Bxf40uRC.js";const p=JSON.parse('{"title":"Linux面试问题","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/面试问题.md","filePath":"Linux/面试问题.md","lastUpdated":null}'),t={name:"Linux/面试问题.md"},n=l('<h1 id="linux面试问题" tabindex="-1">Linux面试问题 <a class="header-anchor" href="#linux面试问题" aria-label="Permalink to &quot;Linux面试问题&quot;">​</a></h1><h2 id="linux系统中-你装了很多软件-这些服务运行起来之后-那每个软件它主要的进程状态-以及它每个软件主要进程占用的资源-究竟用什么方法可以查询到" tabindex="-1">linux系统中，你装了很多软件，这些服务运行起来之后，那每个软件它主要的进程状态，以及它每个软件主要进程占用的资源，究竟用什么方法可以查询到？ <a class="header-anchor" href="#linux系统中-你装了很多软件-这些服务运行起来之后-那每个软件它主要的进程状态-以及它每个软件主要进程占用的资源-究竟用什么方法可以查询到" aria-label="Permalink to &quot;linux系统中，你装了很多软件，这些服务运行起来之后，那每个软件它主要的进程状态，以及它每个软件主要进程占用的资源，究竟用什么方法可以查询到？&quot;">​</a></h2><p>ps aux ，a代表显示所有终端的进程，u代表用户友好格式，x表示显示没有终端控制的进程</p><h2 id="软链接和硬链接的区别" tabindex="-1">软链接和硬链接的区别？ <a class="header-anchor" href="#软链接和硬链接的区别" aria-label="Permalink to &quot;软链接和硬链接的区别？&quot;">​</a></h2><ol><li>软链接是指向目标文件的指针，保存的是目标文件的文件路径，硬链接是一个文件系统的实体文件，它与目标文件共享相同的inode和数据块，实际上是一个文件的多个别名，不包含目标文件的路径名称，而是直接指向对应的inode；</li><li>如果目标文件删除，软链接就会报错；但是如果删除目标文件，硬链接还是可以获取到对应的数据，只有当所有的硬链接都删除了，目标区域的数据才会被释放；</li><li>修改软链接的权限不会影响到目标文件，修改硬链接的权限会影响目标文件；</li></ol><h2 id="什么是inode" tabindex="-1">什么是inode？ <a class="header-anchor" href="#什么是inode" aria-label="Permalink to &quot;什么是inode？&quot;">​</a></h2><p>表示文件或者目录在文件系统下的元数据信息，主要包括：</p><ol><li>文件类型和权限</li><li>文件的所有者和所属组</li><li>文件的大小</li><li>文件的创建时间、修改时间和访问时间</li><li>文件的链接数目</li><li>文件数据的物理位置（对于小文件直接包含数据，对于大文件保存了指向数据块的指针）</li></ol>',8),o=[n];function r(d,s,_,u,c,h){return i(),e("div",null,o)}const m=a(t,[["render",r]]);export{p as __pageData,m as default};
